import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const A=JSON.parse('{"title":"GAAP与真实盈利","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/GAAP与真实盈利.md","filePath":"05_quotes/by-theme/GAAP与真实盈利.md"}'),r={name:"05_quotes/by-theme/GAAP与真实盈利.md"};function q(l,t,c,p,_,s){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="gaap与真实盈利" tabindex="-1">GAAP与真实盈利 <a class="header-anchor" href="#gaap与真实盈利" aria-label="Permalink to &quot;GAAP与真实盈利&quot;">​</a></h1><blockquote><p>&quot;会计准则只是商业现实的参考，而非替代。数字是服务的工具，不是目的本身。&quot;——巴菲特</p></blockquote><p>巴菲特一直批评过度依赖GAAP会计准则，倡导关注真实的经济盈利。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;GAAP规则下的一些数字会严重扭曲真实的经济现实。商誉摊销就是一个典型的例子——每年固定扣除但通常不代表真实损失。&quot;</p></blockquote><blockquote><p>&quot;我们报告的&quot;营业利润&quot;比GAAP数字更能反映我们业务的真实表现。我们不把一次性的资本利得计入营业利润，因为那不代表持续的经营成果。&quot;</p></blockquote><blockquote><p>&quot;会计准则要求我们在股价大幅下跌时确认巨额损失，但在股价上涨时不确认相应收益。这种不对称性是对真实情况的严重扭曲。&quot;</p></blockquote><blockquote><p>&quot;我们的目标是让股东理解真实的经济盈利，而不是被会计规则牵着走。如果你看不懂数字背后的业务，再精确的会计也没有意义。&quot;</p></blockquote><blockquote><p>&quot;我宁愿要一个模糊的正确，也不要一个精确的错误。GAAP有时候给我们的是精确的错误。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1983年 · 1987年 · 1992年 · 2001年 · 2009年 · 2020年</p>',13)])])}const i=o(r,[["render",q]]);export{A as __pageData,i as default};
